document.addEventListener("DOMContentLoaded",function(){document.querySelectorAll(".tptn_counter[data-tptn-url]").forEach(function(t){fetch(t.getAttribute("data-tptn-url")).then(function(t){if(!t.ok)throw new Error("Counter request failed");return t.json()}).then(function(n){n&&n.count&&(t.innerHTML=n.count)}).catch(function(t){console.error("Error:",t)})})});